import Modal from "../../plugins/modals";
export default {
  data() {
    return {
      visible: false,
      positioning: "",
      friend: {}
    };
  },
  methods: {
    hide(event = null) {
      if (event) {
        if (event.target.contains(event.relatedTarget)) {
          event.relatedTarget.click();
          this.visible = false;
        }
      }
      this.visible = false;
    },
    show(params) {
      this.visible = true;
      this.friend = params.friend;
      this.positioning = params.positioning;
    },
    inviteFriend() {
      this.$socket.sendLobbyMessage("LOBBY_INVITE", {
        data: this.friend
      }, (response, error) => {
        if (error) {
          console.log("Flyback error:");
          console.log(error);
        }
      });
    },
    removeFriend() {
      this.$socket.sendSystemMessage("FRIEND_REMOVE", {
        data: this.friend
      }, (response, error) => {
        if (error) {
          console.log("Flyback error:");
          console.log(error);
        }
      });
    },
    blockFriend() {
      this.$socket.sendSystemMessage("FRIEND_BLOCK", {
        data: this.friend
      }, (response, error) => {
        if (error) {
          console.log("Flyback error:");
          console.log(error);
        }
      });
    },
    banUser() {
      this.$socket.sendSystemMessage("USER_BAN", {
        data: this.friend.summonerName
      }, (response, error) => {
        if (error) {
          console.log("Flyback error:");
          console.log(error);
        }
      });
    },
    isAdmin() {
      return this.$store.state.user.roles.includes("ADMIN");
    }
  },
  beforeMount() {
    Modal.EventBus.$on("friend-contextmenu-show", params => {
      this.show(params);
    });
  },
  updated() {
    if (this.$refs.contextmenu) {
      this.$refs.contextmenu.focus();
    }
  }
};
